import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown',
    temperature = 0,
    condition = 'N/A',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card padding={24} shadow="md" radius="lg">
      <Stack gap={24}>
        <div role="region" aria-label="Weather forecast">
          <Heading level={2}>{city}</Heading>

          <Stack direction="horizontal" justify="between" align="center" gap={16}>
            <Stack gap={4}>
              <Text 
                size="4xl" 
                weight="bold" 
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {temperature}°{unit}
              </Text>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition}
              </Text>
            </Stack>

            <Stack gap={4} align="end">
              <Text variant="bodySmall">Humidity: {humidity}%</Text>
              <Text variant="bodySmall">Wind: {windSpeed} km/h</Text>
            </Stack>
          </Stack>
        </div>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Stack direction="horizontal" justify="between">
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="caption">{item.day ?? '—'}</Text>
              <Text size="xl">{item.icon ?? '☁️'}</Text>
              <Text weight="semibold" variant="bodySmall">
                {item.high ?? 0}° / {item.low ?? 0}°
              </Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Heading, 
  Text, 
  Button, 
  Input, 
  TextArea, 
  RadioGroup, 
  Checkbox, 
  Progress,
  Divider,
  Box
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: -1,
    features: [] as string[],
    comments: ''
  });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canGoNext = () => {
    if (step === 1) return formData.name.trim() !== '' && isEmailValid(formData.email);
    if (step === 2) return formData.satisfaction !== -1;
    return true;
  };

  const handleNext = () => setStep(s => Math.min(s + 1, 5));
  const handleBack = () => setStep(s => Math.max(s - 1, 1));

  const handleSubmit = () => {
    setIsSubmitting(true);
    props.onSubmit?.({
      ...formData,
      satisfaction: formData.satisfaction + 1 
    });
  };

  const toggleFeature = (feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature) 
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" padding={32} radius="lg">
        <Stack gap={16}>
          <Heading level={2}>Survey Form</Heading>
          <Text variant="caption">Step {Math.min(step, 4)} of 4</Text>
          <Progress value={(Math.min(step, 4) / 4) * 100} size="sm" />

          <Box paddingY={16}>
            {step === 1 && (
              <Stack gap={16}>
                <Input label="Name" value={formData.name} onChange={(v) => setFormData(f => ({...f, name: v}))} required />
                <Input label="Email" type="email" value={formData.email} onChange={(v) => setFormData(f => ({...f, email: v}))} required error={formData.email && !isEmailValid(formData.email) ? "Invalid email" : undefined} />
              </Stack>
            )}

            {step === 2 && (
              <RadioGroup 
                label="How satisfied are you?" 
                value={formData.satisfaction.toString()} 
                onChange={(v) => setFormData(f => ({...f, satisfaction: parseInt(v)}))}
                options={props.satisfactionLabels.map((l, i) => ({ value: i.toString(), label: l }))}
              />
            )}

            {step === 3 && (
              <Stack gap={8}>
                <Text variant="label">Feature Interests</Text>
                {props.featureOptions.map(opt => (
                  <Checkbox 
                    key={opt} 
                    label={opt} 
                    checked={formData.features.includes(opt)} 
                    onChange={() => toggleFeature(opt)} 
                  />
                ))}
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={16}>
                <TextArea 
                  label="Additional Comments" 
                  value={formData.comments} 
                  onChange={(v) => setFormData(f => ({...f, comments: v}))} 
                  maxLength={500} 
                  showCount 
                />
                <Divider />
                <Heading level={4}>Review Your Answers</Heading>
                <Text variant="bodySmall">Name: {formData.name}</Text>
                <Text variant="bodySmall">Email: {formData.email}</Text>
                <Text variant="bodySmall">Satisfaction: {props.satisfactionLabels[formData.satisfaction]}</Text>
                <Text variant="bodySmall">Features: {formData.features.join(', ') || 'None'}</Text>
              </Stack>
            )}
          </Box>

          <Stack direction="horizontal" justify="between" gap={16}>
            <Button variant="secondary" onClick={handleBack} disabled={step === 1 || isSubmitting}>Back</Button>
            {step < 4 ? (
              <Button onClick={handleNext} disabled={!canGoNext()}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>Submit Survey</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Box,
  Divider,
  Card,
  Heading,
  Text,
  Button,
  Input,
  Select,
  Badge,
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks: Task[];
  columns: Column[];
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId: string; data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [tasks, setTasks] = useState<Task[]>(props.tasks);
  const [isCreating, setIsCreating] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    setTasks(props.tasks);
  }, [props.tasks]);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  const handleUpdate = (action: 'move' | 'edit' | 'create', taskId: string, data: any) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, ...data } : t)));
    props.onTaskUpdate?.({ action, taskId, data });
  };

  const handleCreate = (colId: string) => {
    if (!newTaskTitle.trim()) return;
    setIsSubmitting(true);
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: colId,
      assignee: '??',
    };
    setTasks((prev) => [...prev, newTask]);
    props.onTaskUpdate?.({ action: 'create', taskId: newTask.id!, data: newTask });
    setIsCreating(null);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setIsSubmitting(false);
  };

  const getPriorityVariant = (priority?: string): 'default' | 'warning' | 'error' => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'default';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Box 
          padding="var(--ggui-spacing-4, 16px)" 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="center">
            <Heading level={3}>Task Board</Heading>
            <Divider orientation="vertical" />
            <Text>Total Tasks: {totalTasks}</Text>
            <Text>Completed: {completedTasks}</Text>
          </Stack>
        </Box>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="start" wrap>
          {props.columns.map((col) => (
            <Box
              key={col.id}
              padding="var(--ggui-spacing-4, 16px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
              style={{ flex: 1, minWidth: '300px', border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}
            >
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Heading level={3}>{col.name} ({tasks.filter((t) => t.column === col.id).length})</Heading>

                <Stack gap="var(--ggui-spacing-3, 12px)">
                  {tasks.filter((t) => t.column === col.id).map((task) => (
                    <Card key={task.id} padding="var(--ggui-spacing-3, 12px)" radius="lg">
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        {editingTaskId === task.id ? (
                          <Input label="Task Title" value={editTitle} onChange={setEditTitle} />
                        ) : (
                          <div onDoubleClick={() => { setEditingTaskId(task.id!); setEditTitle(task.title!); }}>
                            <Heading level={6}>{task.title}</Heading>
                          </div>
                        )}
                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant={getPriorityVariant(task.priority)} size="sm">{task.priority ?? 'medium'}</Badge>
                          <Text variant="caption">{task.assignee}</Text>
                        </Stack>
                        <Select
                          label="Move to"
                          value={task.column ?? ''}
                          onChange={(val) => handleUpdate('move', task.id!, { column: val })}
                          options={props.columns.map(c => ({ value: c.id!, label: c.name! }))}
                        />
                        {editingTaskId === task.id && (
                          <Button size="xs" onClick={() => { handleUpdate('edit', task.id!, { title: editTitle }); setEditingTaskId(null); }}>
                            Save
                          </Button>
                        )}
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {isCreating === col.id ? (
                  <Card padding="var(--ggui-spacing-4, 16px)" radius="lg">
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} />
                      <Select 
                        label="Priority" 
                        value={newTaskPriority} 
                        onChange={(v) => setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                        options={[{value:'low', label:'Low'}, {value:'medium', label:'Medium'}, {value:'high', label:'High'}]}
                      />
                      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)">
                        <Button onClick={() => handleCreate(col.id!)} disabled={isSubmitting}>Submit</Button>
                        <Button variant="ghost" onClick={() => setIsCreating(null)}>Cancel</Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" onClick={() => setIsCreating(col.id!)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Box, Text, Heading, Card, Divider } from '@ggui-ai/design/primitives';
import { Input } from '@ggui-ai/design/components';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
  'halogen': 'var(--ggui-color-warning-100, #fef3c7)',
  'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
};

export default function GeneratedComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return props.elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(q) ||
        e.symbol?.toLowerCase().includes(q)
    );
  }, [props.elements, searchQuery]);

  const categories = useMemo(() => {
    return Array.from(new Set(props.elements.map((e) => e.category || 'unknown')));
  }, [props.elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={1}>Periodic Table</Heading>

        <Input
          label="Search elements by name or symbol"
          value={searchQuery}
          onChange={(val) => setSearchQuery(val)}
          placeholder="e.g. Hydrogen or H"
          type="search"
        />

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: 'var(--ggui-spacing-1)',
            padding: 'var(--ggui-spacing-2)',
          }}
        >
          {filteredElements.map((el) => (
            <Box
              key={el.atomicNumber}
              style={{
                gridRow: el.row ?? 'auto',
                gridColumn: el.col ?? 'auto',
                background: CATEGORY_COLORS[el.category || ''] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                padding: 'var(--ggui-spacing-2)',
                cursor: 'pointer',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                transition: 'opacity 200ms ease',
              }}
              onClick={() => setSelectedElement(el)}
              role="button"
              aria-label={`${el.name}, atomic number ${el.atomicNumber}`}
              tabIndex={0}
            >
              <Text variant="caption">{el.atomicNumber}</Text>
              <Heading level={6}>{el.symbol}</Heading>
            </Box>
          ))}
        </Box>

        <Divider margin="var(--ggui-spacing-4)" />

        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
          {categories.map((cat) => (
            <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Box
                style={{
                  width: 16,
                  height: 16,
                  background: CATEGORY_COLORS[cat] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                }}
              />
              <Text variant="caption" style={{ textTransform: 'capitalize' }}>
                {cat.replace('-', ' ')}
              </Text>
            </Stack>
          ))}
        </Stack>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3}>{selectedElement.name}</Heading>
              <Text variant="bodySmall">Symbol: {selectedElement.symbol}</Text>
              <Text variant="bodySmall">Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text variant="bodySmall">Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text variant="bodySmall">Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Card, Box, Text, Heading, Input, Button, Badge, Stack, Spacer } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback for sending a message */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [inputValue, setInputValue] = useState('');
  const [chatMessages, setChatMessages] = useState(props.messages);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatMessages]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail) {
        const { sender, text, timestamp } = customEvent.detail;
        setChatMessages((prev) => [...prev, { sender, text, timestamp }]);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const handleSend = () => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      const newMessage = {
        sender: props.currentUser,
        text: inputValue,
        timestamp,
      };

      setChatMessages((prev) => [...prev, newMessage]);
      props.onSendMessage?.({ text: inputValue, timestamp });
      setInputValue('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card
      shadow="md"
      padding={0}
      border={true}
      radius="lg"
      style={{ height: '500px', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}
    >
      <Box
        padding={16}
        style={{
          borderBottom: '1px solid var(--ggui-color-outlineVariant)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}
      >
        <Heading level={4}>{props.title}</Heading>
        {props.participantCount !== undefined && (
          <Badge variant="secondary">{props.participantCount} participants</Badge>
        )}
      </Box>

      <div style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)' }} ref={scrollRef} role="log" aria-live="polite">
        <Stack gap={16}>
          {chatMessages.map((msg, index) => {
            const isOwn = msg.sender === props.currentUser;
            const prevMsg = chatMessages[index - 1];
            const showName = index === 0 || prevMsg?.sender !== msg.sender;

            return (
              <Stack key={index} align={isOwn ? 'end' : 'start'} gap={4}>
                {showName && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {msg.sender ?? 'Unknown'}
                  </Text>
                )}
                <Box
                  padding={12}
                  borderRadius={8}
                  background={
                    isOwn
                      ? 'var(--ggui-color-primary-600)'
                      : 'var(--ggui-color-surfaceVariant)'
                  }
                  style={{ maxWidth: '80%' }}
                >
                  <Text color={isOwn ? 'white' : 'var(--ggui-color-onSurface)'}>
                    {msg.text}
                  </Text>
                  <Text
                    variant="caption"
                    color={isOwn ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                    style={{ marginTop: 'var(--ggui-spacing-1)' }}
                  >
                    {new Date(msg.timestamp ?? Date.now()).toLocaleTimeString([], {
                      hour: '2-digit',
                      minute: '2-digit',
                    })}
                  </Text>
                </Box>
              </Stack>
            );
          })}
        </Stack>
      </div>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" gap={8} align="center">
          <div style={{ flex: 1 }}>
            <Input
              label="Compose message"
              value={inputValue}
              onChange={(val) => setInputValue(val)}
              placeholder="Type a message..."
              onKeyDown={handleKeyDown}
            />
          </div>
          <Button
            disabled={inputValue.trim() === ''}
            onClick={handleSend}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Heading, 
  Text, 
  Spacer 
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ 
    symbol?: string; 
    name?: string; 
    price?: number; 
    change?: number; 
    changePercent?: number 
  }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [data, setData] = useState(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState(props.lastUpdated ?? new Date().toISOString());

  useEffect(() => {
    const handleData = (event: any) => {
      if (event.detail && Array.isArray(event.detail.stocks)) {
        setData(event.detail.stocks);
        setLastUpdated(event.detail.lastUpdated ?? new Date().toISOString());
      }
    };

    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack direction="horizontal" align="center">
          <Heading level={1}>Market Watch</Heading>
          <Spacer size="flex" />
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
          </Text>
        </Stack>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
          }}
          aria-live="polite"
        >
          {data.length === 0 ? (
            <Text>No stock data available.</Text>
          ) : (
            data.map((stock, index) => {
              const change = stock.change ?? 0;
              const isPositive = change >= 0;
              const statusColor = isPositive ? 'var(--ggui-color-success)' : 'var(--ggui-color-error)';

              return (
                <Card 
                  key={`${stock.symbol ?? index}`} 
                  padding="16px" 
                  shadow="sm" 
                  border={true} 
                  radius="md"
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Heading level={3}>{stock.symbol ?? 'N/A'}</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {stock.name ?? 'Unknown Company'}
                    </Text>
                    <Text size="lg" weight="semibold">
                      ${(stock.price ?? 0).toFixed(2)}
                    </Text>

                    <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)">
                      <Text 
                        variant="label" 
                        color={statusColor} 
                        style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1)' }}
                      >
                        <span role="img" aria-label={isPositive ? 'Price increased' : 'Price decreased'}>
                          {isPositive ? '▲' : '▼'}
                        </span>
                        {Math.abs(change).toFixed(2)} ({Math.abs(stock.changePercent ?? 0).toFixed(2)}%)
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })
          )}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { 
  Container, Card, Stack, Box, Divider, Spacer, Text, Heading, 
  Input, Select, Toggle, RadioGroup, Button, Progress 
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? ''),
    role: props.initialProfile?.role ?? (props.roleOptions[0] ?? ''),
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  const isEmailValid = /^\S+@\S+\.\S+$/.test(formData.email);
  const isStep1Valid = formData.name.trim() !== '' && isEmailValid;

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const update = (key: string, val: any) => setFormData((d) => ({ ...d, [key]: val }));

  const stepContent = useMemo(() => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Input 
              label="Name" 
              value={formData.name} 
              onChange={(v) => update('name', v)} 
              required 
            />
            <Input 
              label="Email" 
              type="email" 
              value={formData.email} 
              onChange={(v) => update('email', v)} 
              error={formData.email && !isEmailValid ? 'Invalid email format' : undefined} 
              required 
            />
            <RadioGroup 
              label="Avatar" 
              direction="horizontal" 
              value={formData.avatar} 
              onChange={(v) => update('avatar', v)} 
              options={props.avatarOptions.map((o) => ({ label: o, value: o }))} 
            />
          </Stack>
        );
      case 2:
        return (
          <Stack gap={16}>
            <Select 
              label="Role" 
              value={formData.role} 
              onChange={(v) => update('role', v)} 
              options={props.roleOptions.map((o) => ({ label: o, value: o }))} 
            />
            <Toggle 
              label="Email Notifications" 
              checked={formData.emailNotifications} 
              onChange={(v) => update('emailNotifications', v)} 
            />
            <RadioGroup 
              label="Theme" 
              direction="horizontal" 
              value={formData.theme} 
              onChange={(v) => update('theme', v)} 
              options={[{ label: 'Light', value: 'light' }, { label: 'Dark', value: 'dark' }]} 
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={12}>
            {Object.entries(formData).map(([k, v]) => (
              <Stack key={k} direction="horizontal" justify="between">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">{k}</Text>
                <Text>{String(v)}</Text>
              </Stack>
            ))}
          </Stack>
        );
      default:
        return null;
    }
  }, [step, formData, props.avatarOptions, props.roleOptions, isEmailValid]);

  return (
    <Container maxWidth="sm" padding={24}>
      <Card shadow="md" padding={24} radius="lg">
        <Stack gap={24}>
          <Stack gap={8}>
            <Heading level={2}>Onboarding - Step {step} / 3</Heading>
            <Progress value={(step / 3) * 100} variant="default" size="md" />
          </Stack>

          <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            {stepContent}
          </Box>

          <Divider />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Go Back</Button>
            {step < 3 ? (
              <Button 
                variant="primary" 
                onClick={handleNext} 
                disabled={step === 1 && !isStep1Valid}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={() => props.onComplete?.(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
